    client_updates = {
        "client_1": {"weights": np.random.rand(10, 10)},
        "client_2": {"weights": np.random.rand(10, 10)}
    }
    aggregated = federated_model.aggregate_updates(client_updates)
    assert isinstance(aggregated, dict)
